package org.example;

import org.junit.Test;

import java.util.HashMap;
import java.util.Map;

import static java.util.Map.entry;
import static org.junit.Assert.*;

public class MorseCodeDecoderTest {
    static HashMap<Integer,Long> foxCounts = new HashMap<>();
    static {
        foxCounts.put(1, 55L);
        foxCounts.put(2, 29L);
        foxCounts.put(3, 23L);
        foxCounts.put(4, 16L);
        foxCounts.put(5, 30L);
        foxCounts.put(6, 22L);
        foxCounts.put(7, 12L);
        foxCounts.put(8, 8L);
        foxCounts.put(9, 3L);
        foxCounts.put(10, 1L);
        foxCounts.put(12, 1L);
        foxCounts.put(13, 1L);
        foxCounts.put(14, 2L);
        foxCounts.put(15, 1L);
        foxCounts.put(17, 1L);
        foxCounts.put(18, 2L);
    }
    static Map<Integer,Long> foxCounts2 = Map.ofEntries(
            entry(2,1L),
            entry(34, 2L),
            entry(35, 3L),
            entry(3, 10L),
            entry(36, 2L),
            entry(4, 42L),
            entry(37, 2L),
            entry(5, 53L),
            entry(6, 36L),
            entry(7, 10L),
            entry(12, 1L),
            entry(13, 3L),
            entry(14, 19L),
            entry(15, 39L),
            entry(16, 24L),
            entry(17, 2L));

    @Test
    public void heyJude() {
        assertEquals("HEY JUDE", MorseCodeDecoder.decodeMorse(MorseCodeDecoder.decodeBitsAdvanced("0000000011011010011100000110000001111110100111110011111100000000000111011111111011111011111000000101100011111100000111110011101100000100000")));
    }

    @Test
    public void brownFox1() {
        assertEquals("THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG", MorseCodeDecoder.decodeMorse(MorseCodeDecoder.decodeBitsAdvanced(
                "")));
    }
    @Test
    public void brownFox2() {
        assertEquals("THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG", MorseCodeDecoder.decodeMorse(MorseCodeDecoder.decodeBitsAdvanced(
                "")));
    }

    @Test
    public void finalTest() {
        assertEquals("TBD", MorseCodeDecoder.decodeMorse(MorseCodeDecoder.decodeBitsAdvanced(
                "")));

    }

    @Test
    public void testLengthBrownFox(){
        MorseCodeDecoder.setStaticValues(foxCounts, 1, 9, 18);
        assertEquals(4, MorseCodeDecoder.getMaxDotLength(1, 1, 9, 18 ));
        assertEquals(10, MorseCodeDecoder.getMaxDashLength(1, 4, 9, 18));
    }

    @Test
    public void test1001(){
        assertEquals("EE", MorseCodeDecoder.decodeMorse((MorseCodeDecoder.decodeBitsAdvanced("1001"))));
    }
    @Test
    public void test10001(){
        assertEquals("EE", MorseCodeDecoder.decodeMorse((MorseCodeDecoder.decodeBitsAdvanced("10001"))));
    }
    @Test
    public void test100001(){
        assertEquals("EE", MorseCodeDecoder.decodeMorse((MorseCodeDecoder.decodeBitsAdvanced("100001"))));
    }
    @Test
    public void test1000001(){
        assertEquals("EE", MorseCodeDecoder.decodeMorse((MorseCodeDecoder.decodeBitsAdvanced("1000001"))));
    }
    @Test
    public void test10000001(){
        assertEquals("E E", MorseCodeDecoder.decodeMorse((MorseCodeDecoder.decodeBitsAdvanced("10000001"))));
    }
    @Test
    public void test10111(){
        assertEquals("A", MorseCodeDecoder.decodeMorse((MorseCodeDecoder.decodeBitsAdvanced("10111"))));
    }

    @Test
    public void test111111100111111(){
        assertEquals("M", MorseCodeDecoder.decodeMorse((MorseCodeDecoder.decodeBitsAdvanced("111111100111111"))));
    }
    @Test
    public void testLength1001(){
        Map<Integer,Long> counts = Map.of(1,2L,    2,1L);
        MorseCodeDecoder.setStaticValues(counts, 1, 1, 2);
        assertEquals(1,  MorseCodeDecoder.getMaxDotLength(1, 2 , 1, 2));
        assertEquals(2,  MorseCodeDecoder.getMaxDashLength(1, 1, 1,2));
    }

    @Test
    public void testLength10001(){
        Map<Integer,Long> counts = Map.of(1,2L,    3,1L);
        MorseCodeDecoder.setStaticValues(counts, 1, 1, 3);
        assertEquals(1,  MorseCodeDecoder.getMaxDotLength(1, 3 , 1, 3));
        assertEquals(3,  MorseCodeDecoder.getMaxDashLength(1, 1, 1,3));
    }
    @Test
    public void testLength100001(){
        Map<Integer,Long> counts = Map.of(1,2L,    4,1L);
        MorseCodeDecoder.setStaticValues(counts, 1, 1, 4);
        assertEquals(1,  MorseCodeDecoder.getMaxDotLength(1, 4 , 1, 4));
        assertEquals(4,  MorseCodeDecoder.getMaxDashLength(1, 1, 1,4));
    }
    @Test
    public void testLength10000001(){
        Map<Integer,Long> counts = Map.of(1,2L,    6,1L);
        MorseCodeDecoder.setStaticValues(counts, 1, 1, 6);
        assertEquals(1,  MorseCodeDecoder.getMaxDotLength(1, 6 , 1, 6));
        assertEquals(5,  MorseCodeDecoder.getMaxDashLength(1, 1, 1,6));
    }
    @Test
    public void testLength10111(){
        Map<Integer,Long> counts = Map.of(1,2L,    3,1L);
        MorseCodeDecoder.setStaticValues(counts, 1, 3, 1);
        assertEquals(1,  MorseCodeDecoder.getMaxDotLength(1, 1 , 3, 1));
        assertEquals(3,  MorseCodeDecoder.getMaxDashLength(1, 1, 3,1));
    }

    @Test
    public void testLength111111100111111(){
        Map<Integer,Long> counts = Map.of(6,1L,    7, 1L,  2,1L);
        MorseCodeDecoder.setStaticValues(counts, 6, 7, 2);
        assertEquals(2,  MorseCodeDecoder.getMaxDotLength(6, 2, 7, 2));
        assertEquals(6,  MorseCodeDecoder.getMaxDashLength(2, 2, 7,2));
    }



}